request.query:
BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?name ?jplElem ?tmtElem WHERE {
  VALUES ?name {
    "Peak%20Power%20inside%20the%20Enclosure"
    "Peak Power inside the Enclosure"
    "Peak%20Power%20Limit%20Requirement"
    "Peak%20Power%20Limit%20Requirement%20"
  }
  OPTIONAL {
    ?jplElem rdf:type vocab:tmt%20requirement .
    ?jplElem vocab:NamedElement_name ?name .
    FILTER(CONTAINS(STR(?jplElem), "JPL"))
  }
  OPTIONAL {
    ?tmtElem rdf:type vocab:tmt%20requirement .
    ?tmtElem vocab:NamedElement_name ?name .
    FILTER(CONTAINS(STR(?tmtElem), "TMT"))
  }
  FILTER(BOUND(?jplElem) || BOUND(?tmtElem))
}
LIMIT 25
